def gen_receive(n, codeword, error_pos : list):
    c = codeword
    for i in range(len(error_pos)):
        pos = n - 1 - error_pos[i]
        bit = c[pos]
        if bit == "1": c = replace_char(c, pos, "0") 
        else: c = replace_char(c, pos, "1")
    
    return c
    
def read_error_pos(filename):
    with open(filename, "r") as file:
        lines = [line.strip() for line in file if line.strip()]
    lines = [int(lines[i]) for i in range(len(lines))]
    m = lines[0]
    error_pos = lines[1:]
    return m, error_pos

def write_received_code(filename, code, m, error_pos):
    "filename: output file name" 
    n = 2 ** m - 1
    r = gen_receive(n, code, error_pos)
    with open(filename, "w") as file:
        file.write(str(m) + "\n")
        file.write(r)
def main(case):
    # fixed codeword, editable error position
    codeword = {
        6: "010010100001111110110100101010001110011010111010101110100000011",
        8: "010010100001111110110100101010001110011010111010101101100010100110000100011001011000101000010101101101000011110011000110011111100011001110000001101011011001100111010010101100011011011001100111111010011011100111000001110110100011001000011110101010010001000",
        10: ""
    }
    filename = f"./error_position/e{case}.txt"
    output_file = f"./received_code/r{case}.txt"
    m, error_pos = read_error_pos(filename)
    assert m==10 or m==8 or m==6
    write_received_code(output_file, codeword[m], m ,error_pos)
    print(f"Generated Received Codeword for case: {case}")

if __name__ == "__main__":
    parser = argparse.ArgumentParser(description='Generate received codeword')
    parser.add_argument('case', type=str, help='Case number')
    args = parser.parse_args()
    
    main(args.case)


